UPDATE archivio_items SET abstract = 'Coprifuoco alcolico scattato alle due di questa notte: indagine a Riccione. Nei ristoranti divieti dappertutto. I gestori dei locali dicono che rispetteranno il divieto, ma sostengono che in altri paesi sono state trovate altre soluzioni, come quella del guidatore designato. L''inviato non ha visto nessun controllo.' WHERE id_originale = 34655;
UPDATE archivio_items SET abstract = 'Due nuove vittime dell'' eroina in poche ore, a Siracusa e nell''ascolano, nei giorni scorsi c''erano stati 3 morti a Roma. Probabile la presenza sul mercato di droga tagliata male..' WHERE id_originale = 34661;
UPDATE archivio_items SET abstract = 'In questo spot vengono mostrate alcune immagini della vita di una donna come se il tempo tornasse indietro. Infatti questo è il punto di forza del prodotto, l''essere in grado di rimuovere fino a dieci anni di macchie.
