UPDATE archivio_items SET abstract = 'I momenti di vita e di crescita di uomini e donne, da quando sono bambini,poi adolescenti, poi ragazzi ed infine genitori ed una voce in sottofondo che ribadisce come ‘loro’ (n.r.d. le marche) siano state sempre presenti in ognuna di queste situazioni, ogni volta che loro ne avevano bisogno
