UPDATE archivio_items SET abstract = 'E'' la città in assoluto più danneggiata dai graffittari. Chi realizza queste scritte contesta soprattutto la società in cui vivono. Nelle interviste i cittadini mostrano di non apprezzare le lordure sui muri. 1 ragazzo su 2 fra i 13 e i 18 anni ha usato almeno una volta una bomboletta spray. Solo a Milano 40.000 i palazzi imbrattati.' WHERE id_originale = 34766;
UPDATE archivio_items SET abstract = 'CONAD SUPERMERCATI - (Voce fuoricampo) "di vini ce ne intendiamo, ne abbiamo stappati, sorseggiati, selezionati. Adesso: provate il nostro Asti spumante DOC a soli 2,50€. Adesso provate Conad" - Le immagini invece scorrono su un tavolo imbandito pieno di cibi e di vini di ogni tipo" - Calim: "Conad, artisti nella qualità. Maestri nella convenienza" - Musica: "sotto questo cielo" di Zucchero.' WHERE id_originale = 34867;
UPDATE archivio_items SET abstract = 'Un campo di calcetto, giochi nuovi e un giardino verdissimo. 
